using Windows.Win32;
using Windows.Win32.Foundation;
using Windows.Win32.UI.Shell;
using Windows.Win32.UI.WindowsAndMessaging;

namespace ClaudeCodeOllamaProxy.UI.Services;

/// <summary>
/// Enforces a minimum size for the main window. WinUI's <see cref="Microsoft.UI.Windowing.AppWindow"/> has
/// no minimum-size property, so this subclasses the native window and answers <c>WM_GETMINMAXINFO</c> with
/// the minimum track size (scaled from DIPs to physical pixels for the window's current DPI). The Win32
/// entry points are generated by CsWin32 from <c>NativeMethods.txt</c>.
/// </summary>
internal static unsafe class WindowMinSizeHelper
{
    private const uint WM_GETMINMAXINFO = 0x0024;
    private const uint SubclassId = 1;

    // Hold the delegate in a static field so it isn't garbage-collected while the subclass is installed.
    private static readonly SUBCLASSPROC Proc = SubclassProc;
    private static int _minWidthDip;
    private static int _minHeightDip;

    /// <summary>Install the minimum-size subclass on <paramref name="hwnd"/> (idempotent per window).</summary>
    public static void Apply(HWND hwnd, int minWidthDip, int minHeightDip)
    {
        if (hwnd.IsNull)
            return;

        _minWidthDip = minWidthDip;
        _minHeightDip = minHeightDip;
        PInvoke.SetWindowSubclass(hwnd, Proc, SubclassId, 0);
    }

    private static LRESULT SubclassProc(HWND hwnd, uint msg, WPARAM wParam, LPARAM lParam, nuint idSubclass, nuint refData)
    {
        if (msg == WM_GETMINMAXINFO && lParam.Value != 0)
        {
            var dpi = PInvoke.GetDpiForWindow(hwnd);
            var scale = dpi == 0 ? 1.0 : dpi / 96.0;

            var info = (MINMAXINFO*)lParam.Value;
            info->ptMinTrackSize.X = (int)(_minWidthDip * scale);
            info->ptMinTrackSize.Y = (int)(_minHeightDip * scale);
            return (LRESULT)0;
        }

        return PInvoke.DefSubclassProc(hwnd, msg, wParam, lParam);
    }
}
